mkdir -p /tmp/sv-9a4b281a86114d4591dec1033496d253/typed-meta && cd /tmp/sv-9a4b281a86114d4591dec1033496d253/typed-meta && dotnet new console --framework net11.0 -o . --force -n TypedMeta >/dev/null 2>&1 && cat > Program.cs << 'EOF'
using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with a known resolver (the default reflection-based one)
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// Round-trip using the typed metadata
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

Person deserialized = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized: {deserialized}");

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
//    Use an options instance with NO resolver to simulate "not available"
var emptyOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new NoOpResolver()
};

if (emptyOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Found metadata: {info!.Type.Name}");
}
else
{
    Console.WriteLine("Metadata for Person is NOT available (no exception thrown).");
}

// Also show the positive case with TryGetTypeInfo
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2))
{
    Console.WriteLine($"TryGetTypeInfo succeeded: {info2!.Type.Name}");
}

Console.WriteLine("Done.");

// --- Types ---

record Person(string Name, int Age);

// A resolver that resolves nothing, to demonstrate TryGetTypeInfo returning false
sealed class NoOpResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}
EOF
